__global__ void bfs_kernel_expand(
    int no_of_nodes,
    const Node* graph_nodes,
    const int* graph_edges,
    bool* graph_mask,
    bool* updating_graph_mask,
    const bool* graph_visited,
    int* cost)
{
    int x_12 = blockIdx.x * blockDim.x + threadIdx.x;
    if (x_12 < no_of_nodes && graph_mask[x_12] == true) {
        graph_mask[x_12] = false;
        int start = graph_nodes[x_12].starting;
        int end = graph_nodes[x_12].starting + graph_nodes[x_12].no_of_edges;
        int next_cost = cost[x_12] + 1;
        for (int i = start; i < end; i++) {
            int x_3 = graph_edges[i];
            if (!graph_visited[x_3]) {
                cost[x_3] = next_cost;
                updating_graph_mask[x_3] = true;
            }
        }
    }
}

__global__ void bfs_kernel_update(
    int no_of_nodes,
    bool* graph_mask,
    bool* updating_graph_mask,
    bool* graph_visited,
    int* stop)
{
    int item_5 = blockIdx.x * blockDim.x + threadIdx.x;
    if (item_5 < no_of_nodes && updating_graph_mask[item_5] == true) {
        graph_mask[item_5] = true;
        graph_visited[item_5] = true;
        *stop = 1;
        updating_graph_mask[item_5] = false;
    }
}

